import { revalidateTag, unstable_cache } from 'next/cache';

let products = [
  { id: 1, name: 'Laptop', price: 999, inventory: 12, availability: 'In stock' },
  { id: 2, name: 'Phone', price: 699, inventory: 24, availability: 'In stock' },
  { id: 3, name: 'Tablet', price: 499, inventory: 0, availability: 'Backordered' },
  { id: 4, name: 'Headphones', price: 199, inventory: 48, availability: 'In stock' },
  { id: 5, name: 'Watch', price: 299, inventory: 8, availability: 'Low stock' }
];

const delay = ms => new Promise(resolve => setTimeout(resolve, ms));

export const getAllProducts = unstable_cache(
  async () => {
    await delay(100);
    return products;
  },
  ['products-catalog'],
  {
    tags: ['products'],
    revalidate: 3600
  }
);

export async function syncLatestCatalog() {
  await delay(1500);

  const syncedAt = new Date().toISOString();

  products = products.map((product, index) => {
    const inventory = Math.max(0, product.inventory + (index % 2 === 0 ? 6 : -3));
    const nextAvailability = inventory > 10 ? 'In stock' : inventory > 0 ? 'Low stock' : 'Backordered';

    return {
      ...product,
      price: Math.round(product.price * (1 + (index + 1) * 0.01)),
      inventory,
      availability: nextAvailability,
      syncedAt
    };
  });

  revalidateTag('products');

  return products;
}

